<style>
:root {
  --accent: #D4537E;
  --muted: #8a8a8a;
  --border: #e4e4e4;
  --text: #1a1a1a;
}

#title-block-header { display: none !important; }

.page-wrap {
  max-width: 860px;
  margin: 0 auto;
  padding: 3rem 1.5rem 5rem;
}

/* ── HERO ── */
.hero {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 3.5rem;
  padding-bottom: 3rem;
}

.headshot {
  width: 160px;
  height: 160px;
  border-radius: 50%;
  object-fit: cover;
  margin-bottom: 1.25rem;
  display: block;
}

.hero-headline {
  font-size: 1.75rem;
  font-weight: 700;
  line-height: 1.4;
  color: var(--text);
  margin: 0 0 1rem;
}

.accent { color: var(--accent); }

.hero-bio {
  color: #5a5a5a;
  font-size: 0.95rem;
  line-height: 1.75;
  margin: 0 0 1.75rem;
}

.cta-row {
  display: flex;
  gap: 0.75rem;
  flex-wrap: wrap;
}

.btn {
  display: inline-block;
  padding: 0.55rem 1.3rem;
  font-size: 0.85rem;
  font-weight: 500;
  border-radius: 4px;
  text-decoration: none;
}
.btn:hover { opacity: 0.82; text-decoration: none; }

.btn-primary {
  background: var(--accent);
  color: #fff;
  border: 1px solid var(--accent);
}

.btn-outline {
  background: transparent;
  color: var(--accent);
  border: 1px solid var(--accent);
}

/* Stat grid */
.stat-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
  margin-bottom: 1.25rem;
}

.stat-box {
  border: 1px solid var(--border);
  border-radius: 4px;
  padding: 1.1rem 1.25rem;
}

.stat-number {
  display: block;
  font-size: 1.6rem;
  font-weight: 700;
  color: var(--text);
  line-height: 1.2;
}

.stat-label {
  display: block;
  font-size: 0.72rem;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  color: var(--muted);
  margin-top: 0.25rem;
  line-height: 1.4;
}

/* Skill chips */
.chip-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
}

.chip {
  border: 1px solid var(--accent);
  color: var(--accent);
  background: transparent;
  font-size: 0.78rem;
  padding: 0.22rem 0.75rem;
  border-radius: 999px;
  white-space: nowrap;
}

/* ── DIVIDER ── */
.section-hr {
  border: none;
  border-top: 1px solid var(--border);
  margin: 3rem 0;
}

/* ── SECTION LABEL ── */
.section-label {
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.15em;
  color: var(--muted);
  font-weight: 600;
  margin: 0 0 1.75rem;
}

/* ── TIMELINE ── */
.timeline-entry {
  display: grid;
  grid-template-columns: 140px 1fr;
  gap: 1.75rem;
  margin-bottom: 2.25rem;
}

.tl-date {
  font-size: 0.78rem;
  color: var(--muted);
  line-height: 1.6;
  padding-top: 0.15rem;
}

.tl-role {
  font-size: 0.95rem;
  font-weight: 600;
  color: var(--text);
  margin: 0 0 0.15rem;
}

.tl-org {
  font-size: 0.85rem;
  color: var(--accent);
  margin: 0 0 0.5rem;
}

.tl-desc {
  font-size: 0.875rem;
  color: #5a5a5a;
  line-height: 1.65;
  margin: 0;
}

/* ── NOW CARD ── */
.now-card {
  border: 1px solid var(--border);
  border-radius: 4px;
  padding: 1.5rem;
}

.now-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 0.75rem;
}

.now-live {
  display: flex;
  align-items: center;
  gap: 0.4rem;
}

.live-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--accent);
  display: inline-block;
  animation: pulse 2s infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.4; }
}

.live-label {
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--accent);
  font-weight: 700;
}

.now-date-badge {
  font-size: 0.75rem;
  color: var(--muted);
  border: 1px solid var(--border);
  padding: 0.15rem 0.65rem;
  border-radius: 999px;
}

.now-project {
  font-size: 1.05rem;
  font-weight: 700;
  color: var(--text);
  margin-bottom: 0.2rem;
}

.now-subtitle {
  font-size: 0.8rem;
  color: var(--accent);
  margin-bottom: 1.25rem;
}

.now-fields {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1.25rem;
  margin-bottom: 1.25rem;
}

.now-field-label {
  display: block;
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--muted);
  font-weight: 600;
  margin-bottom: 0.3rem;
}

.now-field-value {
  font-size: 0.82rem;
  color: #5a5a5a;
  line-height: 1.6;
}

.now-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 0.35rem;
}

.now-tag {
  font-size: 0.75rem;
  padding: 0.2rem 0.65rem;
  border-radius: 999px;
  border: 1px solid var(--border);
  color: var(--muted);
  background: transparent;
}

.now-tag.accent-tag {
  border-color: var(--accent);
  color: var(--accent);
}

/* ── ARCHIVE TABLE ── */
.archive-table {
  width: 100%;
  border-collapse: collapse;
}

.archive-table th {
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  color: var(--muted);
  font-weight: 600;
  text-align: left;
  padding: 0.6rem 1rem 0.6rem 0;
  border-bottom: 1px solid var(--border);
}

.archive-table td {
  padding: 0.7rem 1rem 0.7rem 0;
  border-bottom: 1px solid var(--border);
  color: var(--text);
  font-size: 0.875rem;
}

.archive-table .archive-tags {
  color: var(--muted);
  font-size: 0.8rem;
}

@media (max-width: 680px) {
  .hero { grid-template-columns: 1fr; gap: 2rem; }
  .timeline-entry { grid-template-columns: 1fr; gap: 0.35rem; }
  .now-fields { grid-template-columns: 1fr; }
}
</style>

